import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testWithIgnoreEmptyLines() {
        // Given
        boolean ignoreEmptyLines = true;
        CSVFormat csvFormat = new CSVFormat('|', '"', QuoteMode.ALL_NON_NULL, '#', '\\', false, false, "\n",
                "NULL", new Object[] { "Header Comments" }, new String[] { "Header1", "Header2" }, false, true, true,
                true, true);

        // When
        CSVFormat newCsvFormat = csvFormat.withIgnoreEmptyLines(ignoreEmptyLines);

        // Then
        assertEquals(ignoreEmptyLines, newCsvFormat.getIgnoreEmptyLines());
        assertEquals('|', newCsvFormat.getDelimiter());
        assertEquals('"', newCsvFormat.getQuoteCharacter());
        assertEquals(QuoteMode.ALL_NON_NULL, newCsvFormat.getQuoteMode());
        assertEquals('#', newCsvFormat.getCommentMarker());
        assertEquals('\\', newCsvFormat.getEscapeCharacter());
        assertEquals(false, newCsvFormat.getIgnoreSurroundingSpaces());
        assertEquals(ignoreEmptyLines, newCsvFormat.getIgnoreEmptyLines());
        assertEquals("\n", newCsvFormat.getRecordSeparator());
        assertEquals("NULL", newCsvFormat.getNullString());
        assertEquals("Header Comments", newCsvFormat.getHeaderComments()[0]);
        assertEquals("Header1", newCsvFormat.getHeader()[0]);
        assertEquals("Header2", newCsvFormat.getHeader()[1]);
        assertEquals(false, newCsvFormat.getSkipHeaderRecord());
        assertEquals(true, newCsvFormat.getAllowMissingColumnNames());
        assertEquals(true, newCsvFormat.getIgnoreHeaderCase());
        assertEquals(true, newCsvFormat.getTrim());
        assertEquals(true, newCsvFormat.getTrailingDelimiter());
    }
}
